module packet_filter (
    input [15:0] source_ip,
    input [15:0] dest_ip,
    output reg allow
);
    always @(*) begin
        if ((source_ip >= 16'hC0A8_0001) && (source_ip <= 16'hC0A8_00FF) && (dest_ip == 16'hC0A8_000A)) 
            allow = 1;
        else
            allow = 0;
    end
endmodule
